package br.com.portfolio.ecommerce.catalog.domain;
import br.com.portfolio.ecommerce.shared.domain.*; import java.util.*;
public class Product { private final UUID id; private final String sku; private final String name; private final Money price; private final boolean active; public Product(UUID id,String sku,String name,Money price,boolean active){this.id=id;this.sku=sku;this.name=name;this.price=price;this.active=active;} public void ensureSellable(){ if(!active) throw new BusinessException("Produto inativo: "+sku); } public UUID id(){return id;} public String sku(){return sku;} public String name(){return name;} public Money price(){return price;} public boolean active(){return active;} }
